import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Booking from './pages/Booking';
import About from './pages/About';
import Gallery from './pages/Gallery';
import Contact from './pages/Contact';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';

function App() {
  return (
    <Router>
      {/* Navigation Bar */}
      <nav className="bg-gradient-to-r from-amber-900 to-orange-800 text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            {/* Logo */}
            <Link to="/" className="text-2xl font-bold flex items-center gap-2">
              🐯 Ranthambhore Safari
            </Link>
            
            {/* Menu Links */}
            <div className="hidden md:flex gap-8">
              <Link to="/" className="hover:text-amber-200 transition">Home</Link>
              <Link to="/booking" className="hover:text-amber-200 transition">Booking</Link>
              <Link to="/gallery" className="hover:text-amber-200 transition">Gallery</Link>
              <Link to="/about" className="hover:text-amber-200 transition">About</Link>
              <Link to="/contact" className="hover:text-amber-200 transition">Contact</Link>
            </div>

            {/* Admin Link */}
            <Link to="/admin/login" className="bg-green-600 hover:bg-green-700 px-4 py-2 rounded-lg transition">
              Admin
            </Link>
          </div>
        </div>
      </nav>

      {/* Routes */}
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/booking" element={<Booking />} />
        <Route path="/about" element={<About />} />
        <Route path="/gallery" element={<Gallery />} />
        <Route path="/contact" element={<Contact />} />
        <Route path="/admin/login" element={<AdminLogin />} />
        <Route path="/admin/dashboard" element={<AdminDashboard />} />
      </Routes>
    </Router>
  );
}

export default App;
